222	```ts
223	import { AsyncLocalStorage } from 'node:async_hooks';
224	import { APIError } from 'better-auth';
225	
226	/**
227	 * Request-scoped carrier for the session token better-auth mints during a
228	 * sign-in flow. handler.ts's databaseHooks.session.create.after writes
229	 * box.token; plugin.ts's forwardToBetterAuth runs the better-auth call inside
230	 * sessionTokenALS.run(box, ...) and re-issues the token as the http-server-
231	 * signed ax_auth_session cookie. Keeps auth_better_v1_sessions + ax_auth_session
232	 * the single source of truth even though better-auth would set its own cookie.
233	 */
234	export const sessionTokenALS = new AsyncLocalStorage<{ token?: string }>();
235	
236	/** Parse the provider's allowed_domains (comma-separated) into lowercased bare domains. */
237	export function parseDomains(raw: string | null | undefined): string[] {
238	  if (typeof raw !== 'string') return [];
239	  return raw.split(',').map((d) => d.trim().toLowerCase()).filter((d) => d.length > 0);
240	}
241	
242	/** Domain portion of an email (after the last @), lowercased; '' if malformed. */
243	export function emailDomain(email: string): string {
244	  const at = email.lastIndexOf('@');
245	  if (at < 0 || at === email.length - 1) return '';
246	  return email.slice(at + 1).toLowerCase();
247	}
248	
249	/**
250	 * Authorization gate for Google provisioning. Empty `allowed` => open. Throws
251	 * better-auth's APIError (FORBIDDEN) so a rejected sign-in becomes a clean
252	 * callback-error redirect, not a 500. Message is generic (never echoes the list).
253	 */
254	export function assertDomainAllowed(email: string, allowed: string[]): void {
255	  if (allowed.length === 0) return;
256	  if (!allowed.includes(emailDomain(email))) {
257	    throw new APIError('FORBIDDEN', { message: 'email domain not permitted' });
258	  }
259	}
260	```
