462	```ts
463	import { sessionTokenALS } from './session-bridge.js';
464	
465	// Pinned via advanced.cookiePrefix='ax_better_auth' in handler.ts. The bridge
466	// doesn't match on it (the box.token branch drops ALL better-auth cookies on
467	// a session-creating response); kept as a named constant so the coupling is explicit.
468	const BETTER_AUTH_SESSION_COOKIE = 'ax_better_auth.session_token';
469	
470	interface BridgeOpts { sessionCookieName: string; sessionLifetimeSeconds: number; }
471	
472	async function forwardToBetterAuth(
473	  handle: HandlerHandle, req: HttpRequest, res: HttpResponse, bridge: BridgeOpts,
474	): Promise<void> {
475	  const host = req.headers['host'] ?? 'localhost';
476	  const proto = req.headers['x-forwarded-proto'] ?? 'http';
477	  const queryString = serializeQuery(req.query);
478	  const url = `${proto}://${host}${req.path}${queryString.length > 0 ? `?${queryString}` : ''}`;
479	
480	  const init: RequestInit = { method: req.method, headers: webHeadersFrom(req.headers) };
481	  if (req.method !== 'GET' && req.body.length > 0) {
482	    init.body = req.body as unknown as ArrayBuffer;
483	  }
484	
485	  const box: { token?: string } = {};
486	  let webResponse: Response;
487	  try {
488	    webResponse = await sessionTokenALS.run(box, () => handle.current()(new Request(url, init)));
489	  } catch (err) {
490	    void err;
491	    process.stderr.write(`[ax/auth-better] handler error on ${req.method} ${req.path}\n`);
492	    res.status(500).json({ error: 'auth-handler-failed' });
493	    return;
494	  }
495	
496	  res.status(webResponse.status);
497	  const setCookies = readSetCookies(webResponse.headers);
498	  for (const [name, value] of webResponse.headers.entries()) {
499	    if (name.toLowerCase() === 'set-cookie') continue;
500	    res.header(name, value);
501	  }
502	
503	  if (box.token !== undefined) {
504	    // Session-creating response (OAuth callback / email sign-in): re-issue the
505	    // session token as our http-server-signed cookie. better-auth's own
506	    // Set-Cookies on this response are intentionally dropped — its session
507	    // cookie is replaced by ours; its short-lived OAuth-state cookie self-expires.
508	    // (http-server writeHead() overwrites a header-map 'set-cookie' with the
509	    // setCookies[] array, so setSignedCookie alone yields the right wire output.)
510	    res.setSignedCookie(bridge.sessionCookieName, box.token, {
511	      path: '/', sameSite: 'Lax',
512	      ...(process.env['NODE_ENV'] === 'production' ? { secure: true } : {}),
513	      maxAge: bridge.sessionLifetimeSeconds,
514	    });
515	  } else if (setCookies.length > 0) {
516	    // Non-session responses (e.g. /sign-in/social sets the OAuth-state cookie):
517	    // forward better-auth's cookies unchanged.
518	    res.header('set-cookie', setCookies.join(', '));
519	  }
520	
521	  const buf = Buffer.from(await webResponse.arrayBuffer());
522	  if (buf.length === 0) res.end();
523	  else res.body(buf);
524	}
525	```
