1	/**
2	 * @ax/auth-better public hook payload types.
3	 *
4	 * BOUNDARY CONTRACT — these types are the auth alternate-impl boundary
5	 * (mirrors the `@ax/sandbox-k8s` / `@ax/sandbox-subprocess` pattern).
6	 * A future `@ax/auth-saml`, `@ax/auth-passkeys`, or any other auth plugin
7	 * MUST register the same hook surface with the same shapes. Consumers
8	 * (`@ax/agents`, the chat orchestrator, the CLI bootstrap, channel-web)
9	 * resolve users only through the bus — they MUST NOT duplicate the
10	 * `User` type or speak directly to `auth_better_v1_*` tables.
11	 *
12	 * Lock-ins keeping the swap cheap:
13	 *   1. `User` lives here only. Consumers reference this type, never copy
14	 *      it. Drift = boundary violation. If a consumer needs a subset
15	 *      (`{userId, isAdmin}` for an actor payload), that's fine — subsets
16	 *      don't break alternate impls.
17	 *   2. Tenant tables (`auth_better_v1_*`) are scoped to this package's
18	 *      `migrations.ts` + `plugin.ts`. Alternate impls own their own tables.
19	 *   3. IdP-callback error sanitization is part of the contract, not the
20	 *      impl: an alternate auth plugin MUST log only `error.code`,
21	 *      NEVER `error.message` (raw IdP errors carry user-controlled
22	 *      `state` and other request echoes).
23	 *
24	 * NOTE on `HttpRequestLike`: this plugin MUST NOT import from
25	 * `@ax/http-server` (Invariant I2 — no cross-plugin imports). To accept a
26	 * request adapter without that import, we declare the structural minimum we
27	 * need locally. `@ax/http-server`'s `HttpRequest` duck-types compatibly
28	 * because TypeScript's structural typing checks shape, not nominal type.
29	 * Keeping the surface minimal (cookies + headers) means a future
30	 * alternate-impl could provide it from a non-HTTP transport with no extra
31	 * coupling.
32	 */
33	export interface HttpRequestLike {
34	  readonly headers: Record<string, string>;
35	  /**
36	   * Returns the verified plaintext for an HMAC-signed cookie, or null if
37	   * absent / malformed / forged. Constant-time comparison; never throws.
38	   */
39	  signedCookie(name: string): string | null;
40	}
41	
42	/**
43	 * Authenticated user as seen by every consumer (chat path, admin
44	 * endpoints, CLI). This is the boundary type — DO NOT redefine in
45	 * consumers. If a future field lands (e.g., `mfaEnrolled`), add it here
46	 * and let TypeScript surface every consumer that needs to handle it.
47	 */
48	export interface User {
49	  id: string;
50	  email: string | null;
51	  displayName: string | null;
52	  isAdmin: boolean;
53	}
54	
55	export interface RequireUserInput {
56	  req: HttpRequestLike;
57	}
58	
59	export interface RequireUserOutput {
60	  user: User;
61	}
62	
63	export interface GetUserInput {
64	  userId: string;
65	}
66	
67	export type GetUserOutput = User | null;
68	
69	export interface CreateBootstrapUserInput {
70	  displayName: string;
71	  email?: string;
72	  /**
73	   * Forward-compat: a future local-password slice will hash + persist this
74	   * via better-auth's credential account. Today it is accepted but ignored
75	   * by the auth-better impl (see plugin.ts `createBootstrapUser`).
76	   */
77	  password?: string;
78	}
79	
80	export interface CreateBootstrapUserOutput {
81	  user: User;
82	  /**
83	   * Single-use token the bootstrap CLI exchanges for a session cookie.
84	   * NEVER returned via `auth:require-user` / `auth:get-user` (Invariant I9 —
85	   * tokens never leak through hook return values).
86	   */
87	  oneTimeToken: string;
88	}
89	
