1	import { randomBytes } from 'node:crypto';
2	import {
3	  PluginError,
4	  makeAgentContext,
5	  type AgentContext,
6	  type HookBus,
7	  type Plugin,
8	} from '@ax/core';
9	import { sql, type Kysely } from 'kysely';
10	// Type-only import from `@ax/http-server` — we never import a runtime value
11	// from a peer plugin (Invariant I2 — no cross-plugin imports). TypeScript's
12	// `verbatimModuleSyntax: true` plus `import type {...}` guarantees the
13	// emit drops the import entirely. The dev-dep entry in package.json is
14	// type-only.
15	import type {
16	  HttpMethod,
17	  HttpRegisterRouteInput,
18	  HttpRegisterRouteOutput,
19	  HttpRequest,
20	  HttpResponse,
21	} from '@ax/http-server';
22	import type {
23	  CompleteBootstrapUserInput,
24	  CompleteBootstrapUserOutput,
25	  CreateBootstrapUserInput,
26	  CreateBootstrapUserOutput,
27	  HttpRequestLike,
28	  User,
29	} from './types.js';
30	import { runAuthBetterMigration, type AuthBetterDatabase } from './migrations.js';
31	import {
32	  createBetterAuthHandler,
33	  type HandlerHandle,
34	  type ProviderRow,
35	} from './handler.js';
36	import {
37	  createProvidersStore,
38	  type CredentialsEnvelope,
39	  type ProvidersStore,
40	} from './providers-store.js';
41	
42	const PLUGIN_NAME = '@ax/auth-better';
43	const DEFAULT_SESSION_COOKIE_NAME = 'ax_auth_session';
44	const DEFAULT_SESSION_LIFETIME_SECS = 7 * 24 * 60 * 60;
45	
46	// Validation rails for `auth:create-bootstrap-user` input. The bootstrap
47	// caller is the unauthenticated UI — input is untrusted (Invariant I5).
48	// `displayName` is shown verbatim in the admin UI; cap so a giant string
49	// can't blow up the row. `email` is a basic well-formed check (no MX
50	// lookup): keep it cheap, lean on the DB UNIQUE for collision detection.
51	const MAX_DISPLAY_NAME_LEN = 200;
52	const MAX_EMAIL_LEN = 320;
53	const EMAIL_RE = /^[^@\s]+@[^@\s]+$/;
54	
55	/**
56	 * Config surface for `@ax/auth-better`. All fields optional; defaults
57	 * keep cookie behavior stable.
58	 */
59	export interface AuthBetterConfig {
60	  /** Cookie name for the http login session. Default 'ax_auth_session'. */
61	  sessionCookieName?: string;
62	  /** Session lifetime in seconds. Default 7 days. */
63	  sessionLifetimeSeconds?: number;
64	  /**
65	   * Origins better-auth considers trusted for sign-in / OAuth callback / CSRF
66	   * protection. Each entry is a full origin like `https://ax.example.com` or
67	   * `http://localhost:8080`.
68	   *
69	   * Default: `['*']` (test-friendly; production hosts SHOULD pin). Pass a
70	   * concrete list to lock down better-auth's CSRF gate. Multiple origins are
71	   * fine — common pattern is one canonical public URL plus localhost for
72	   * port-forward debugging.
73	   */
74	  trustedOrigins?: string[];
75	}
76	
77	// ---------------------------------------------------------------------------
78	// @ax/auth-better — Task 1.4 lights up the hook surface declared in 1.3.
79	//
80	// What's new vs. 1.3:
81	//   - Real impls for auth:require-user, auth:get-user, auth:create-bootstrap-user
82	//   - `/auth/*` splat route forwards to better-auth's WebStandards handler
83	//   - auth:providers-changed subscriber rebuilds the handler in place
84	//
85	// What's deferred to 1.5:
86	//   - /admin/auth/providers/* CRUD routes (the FIRER of providers-changed)
87	//   - credentials:envelope-encrypt/decrypt declaration in manifest.calls
88	//     — Task 1.5 adds them when CRUD actually wires envelope-encrypt.
89	//     Today loadProviders() short-circuits on empty result sets, so the
90	//     plugin boots without a credentials peer (test-friendly).
91	//
92	// Half-wired window: the auth:providers-changed subscriber is wired today
93	// but no FIRER exists yet. That's fine — the rebuild path is reachable
94	// from contract tests by firing the hook directly. Task 1.5 closes the
95	// window by adding the CRUD route that fires it.
96	// ---------------------------------------------------------------------------
97	
98	export function createAuthBetterPlugin(config: AuthBetterConfig = {}): Plugin {
99	  let db: Kysely<AuthBetterDatabase> | undefined;
100	  let handle: HandlerHandle | undefined;
101	  let busRef: HookBus | undefined;
102	  const unregisterRoutes: Array<() => void> = [];
103	
104	  const sessionCookieName = config.sessionCookieName ?? DEFAULT_SESSION_COOKIE_NAME;
105	  const sessionLifetimeSeconds =
106	    config.sessionLifetimeSeconds ?? DEFAULT_SESSION_LIFETIME_SECS;
107	  // Capture trustedOrigins at construction so the providers-changed
108	  // subscriber doesn't have to re-read config on every fire — config is
109	  // already captured by the closure, but pinning it here is one less
110	  // hop and makes the rebuild call site read straight.
111	  const trustedOrigins = config.trustedOrigins;
112	
113	  const PROVIDERS_CHANGED_KEY = `${PLUGIN_NAME}/providers-changed`;
114	  const RESET_CLEANUP_KEY = `${PLUGIN_NAME}/bootstrap-reset-cleanup`;
115	
116	  return {
117	    manifest: {
118	      name: PLUGIN_NAME,
119	      version: '0.0.0',
120	      registers: [
121	        'auth:require-user',
122	        'auth:get-user',
123	        'auth:create-bootstrap-user',
124	        'auth:complete-bootstrap-user',
125	      ],
126	      // Task 1.5 adds the envelope hooks to `calls` because the admin
127	      // provider CRUD routes now wrap/unwrap secrets unconditionally
128	      // (they encrypt on insert and decrypt on list). Hosts loading
129	      // @ax/auth-better MUST also load @ax/credentials — verifyCalls()
130	      // catches the misconfiguration at boot. Bootstrap-user contract
131	      // tests that don't need providers mock the envelope hooks via
132	      // `services:` on the test harness.
133	      calls: [
134	        'database:get-instance',
135	        'http:register-route',
136	        'credentials:envelope-encrypt',
137	        'credentials:envelope-decrypt',
138	      ],
139	      subscribes: ['auth:providers-changed', 'bootstrap:reset-cleanup'],
140	    },
141	
142	    async init({ bus }) {
143	      busRef = bus;
144	      const initCtx = makeAgentContext({
145	        sessionId: 'init',
146	        agentId: PLUGIN_NAME,
147	        userId: 'system',
148	      });
149	
150	      // 1) DB + migration ------------------------------------------------
151	      const { db: shared } = await bus.call<unknown, { db: Kysely<unknown> }>(
152	        'database:get-instance',
153	        initCtx,
154	        {},
155	      );
156	      db = shared as Kysely<AuthBetterDatabase>;
157	      await runAuthBetterMigration(db);
158	      const localDb = db;
159	
160	      // 2) Initial provider load + store -------------------------------
161	      // The store wraps DB access and hides the envelope plumbing. The
162	      // envelope closure routes through `credentials:envelope-encrypt`
163	      // / `-decrypt`; both live in @ax/credentials, declared in `calls`
164	      // so verifyCalls() catches a missing peer at boot.
165	      const envelope: CredentialsEnvelope = {
166	        async encrypt(plaintext: string): Promise<Uint8Array> {
167	          const { ciphertext } = await bus.call<
168	            { plaintext: string },
169	            { ciphertext: Uint8Array }
170	          >('credentials:envelope-encrypt', initCtx, { plaintext });
171	          return ciphertext;
172	        },
173	        async decrypt(ciphertext: Uint8Array): Promise<string> {
174	          const { plaintext } = await bus.call<
175	            { ciphertext: Uint8Array },
176	            { plaintext: string }
177	          >('credentials:envelope-decrypt', initCtx, { ciphertext });
178	          return plaintext;
179	        },
180	      };
181	      const store = createProvidersStore(localDb, envelope);
182	      const providers = await loadProviders(localDb, bus, initCtx);
183	
184	      // 3) Build the handler --------------------------------------------
185	      handle = createBetterAuthHandler({
186	        database: localDb,
187	        providers,
188	        ...(trustedOrigins !== undefined ? { trustedOrigins } : {}),
189	      });
190	      const localHandle = handle;
191	
192	      // 4) Subscribe to providers-changed for hot-reload -----------------
193	      // Task 1.5's CRUD routes fire `auth:providers-changed` after every
194	      // insert/update/delete; we re-read the table and rebuild the
195	      // handler. The handler-wrapper's catch path (handler.ts) keeps the
196	      // OLD instance live if construction throws, so a typo'd config
197	      // doesn't take down the auth surface mid-flight.
198	      bus.subscribe(
199	        'auth:providers-changed',
200	        PROVIDERS_CHANGED_KEY,
201	        async (subCtx: AgentContext) => {
202	          const next = await loadProviders(localDb, bus, subCtx);
203	          localHandle.rebuild({
204	            database: localDb,
205	            providers: next,
206	            ...(trustedOrigins !== undefined ? { trustedOrigins } : {}),
207	          });
208	          return undefined;
209	        },
210	      );
211	
212	      // Bootstrap-reset cleanup: when an operator runs `ax admin
213	      // reset-bootstrap --force`, wipe the leftover admin user + sessions
214	      // so the next wizard run can complete (auth:create-bootstrap-user
215	      // refuses to mint a second admin while one exists — see I6 gate).
216	      // The handler keeps its in-memory provider catalog; only user/
217	      // session rows are dropped. Runs on the same Kysely instance the
218	      // handler uses, so a wipe-while-handler-serves race is bounded by
219	      // the table-level lock TRUNCATE takes.
220	      bus.subscribe(
221	        'bootstrap:reset-cleanup',
222	        RESET_CLEANUP_KEY,
223	        async () => {
224	          await sql`TRUNCATE auth_better_v1_sessions, auth_better_v1_users CASCADE`.execute(
225	            localDb,
226	          );
227	          return undefined;
228	        },
229	      );
230	
231	      // 5) Service hooks -------------------------------------------------
232	      bus.registerService<{ req: HttpRequestLike }, { user: User }>(
233	        'auth:require-user',
234	        PLUGIN_NAME,
235	        async (_ctx, input) => requireUser(localDb, sessionCookieName, input.req),
236	      );
237	
238	      bus.registerService<{ userId: string }, User | null>(
239	        'auth:get-user',
240	        PLUGIN_NAME,
241	        async (_ctx, input) => getUserById(localDb, input.userId),
242	      );
243	
244	      bus.registerService<CreateBootstrapUserInput, CreateBootstrapUserOutput>(
245	        'auth:create-bootstrap-user',
246	        PLUGIN_NAME,
247	        async (_ctx, input) =>
248	          createBootstrapUser(localDb, sessionLifetimeSeconds, input),
249	      );
250	
251	      bus.registerService<CompleteBootstrapUserInput, CompleteBootstrapUserOutput>(
252	        'auth:complete-bootstrap-user',
253	        PLUGIN_NAME,
254	        async (_ctx, input) => {
255	          // The oneTimeToken IS a sessionId pre-minted by the create hook.
256	          // We just package it as a cookie. We do NOT validate it here — the
257	          // route layer is the auth gate.
258	          // `password` is accepted in the input type for forward-compat with
259	          // Phase 3 local-auth plans but is silently ignored for now (no
260	          // local password support yet; deferred per YAGNI guard in plan).
261	          return {
262	            sessionCookie: {
263	              name: sessionCookieName,
264	              value: input.oneTimeToken,
265	              opts: {
266	                path: '/',
267	                sameSite: 'Lax',
268	                // Production: cookie only over HTTPS. Dev/test: omit so kind
269	                // and local docker work over plain HTTP.
270	                ...(process.env['NODE_ENV'] === 'production' ? { secure: true } : {}),
271	                maxAge: sessionLifetimeSeconds,
272	              },
273	            },
274	          };
275	        },
276	      );
277	
278	      // 6) Mount /auth/* via http:register-route -------------------------
279	      // better-auth's handler is `(req: Request) => Promise<Response>`
280	      // (WebStandards). It does its own internal routing across the
281	      // sign-up / sign-in / sign-out / session / OAuth-callback surface.
282	      // We expose a single splat per HTTP verb and forward through the
283	      // adapter — saves a brittle finite-list of paths drifting against
284	      // better-auth releases.
285	      //
286	      // The router accepts `/*` splats per `Router.compilePathPattern`
287	      // (see http-server/src/router.ts); the captured remainder lands in
288	      // `req.params['*']`, but we don't need it — we reconstruct the URL
289	      // from `req.path` directly (the original path is preserved).
290	      const splatMethods: HttpMethod[] = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'];
291	      for (const method of splatMethods) {
292	        const handler = async (req: HttpRequest, res: HttpResponse): Promise<void> => {
293	          await forwardToBetterAuth(localHandle, req, res);
294	        };
295	        const { unregister } = await bus.call<HttpRegisterRouteInput, HttpRegisterRouteOutput>(
296	          'http:register-route',
297	          initCtx,
298	          { method, path: '/auth/*', handler },
299	        );
300	        unregisterRoutes.push(unregister);
301	      }
302	
303	      // 6.5) /admin/me + /admin/sign-out — channel-web's `lib/auth.ts`
304	      // calls these. Without them, static-files's SPA fallback would
305	      // catch /admin/me and return index.html — the SPA's getSession()
306	      // would then see no user field and treat every fresh sign-in as
307	      // unauthenticated.
308	      {
309	        const meHandler = async (req: HttpRequest, res: HttpResponse): Promise<void> => {
310	          try {
311	            const { user } = await requireUser(localDb, sessionCookieName, req);
312	            res.status(200).json({ user });
313	          } catch {
314	            res.status(401).json({ error: 'unauthenticated' });
315	          }
316	        };
317	        const { unregister } = await bus.call<HttpRegisterRouteInput, HttpRegisterRouteOutput>(
318	          'http:register-route',
319	          initCtx,
320	          { method: 'GET', path: '/admin/me', handler: meHandler },
321	        );
322	        unregisterRoutes.push(unregister);
323	      }
324	
325	      {
326	        const signOutHandler = async (req: HttpRequest, res: HttpResponse): Promise<void> => {
327	          // Idempotent — absent / forged cookie still returns 200 so the
328	          // endpoint isn't a session-existence oracle. Best-effort delete.
329	          const sessionId = req.signedCookie(sessionCookieName);
330	          if (sessionId !== null) {
331	            await localDb
332	              .deleteFrom('auth_better_v1_sessions')
333	              .where('token', '=', sessionId)
334	              .execute();
335	          }
336	          res.clearCookie(sessionCookieName, { path: '/', sameSite: 'Lax' });
337	          res.status(200).json({ ok: true });
338	        };
339	        const { unregister } = await bus.call<HttpRegisterRouteInput, HttpRegisterRouteOutput>(
340	          'http:register-route',
341	          initCtx,
342	          { method: 'POST', path: '/admin/sign-out', handler: signOutHandler },
343	        );
344	        unregisterRoutes.push(unregister);
345	      }
346	
347	      // 7) /admin/auth/providers/* — runtime CRUD (closes I10) ----------
348	      // These routes are the FIRER of `auth:providers-changed`. The
349	      // subscriber registered above re-reads the table and rebuilds the
350	      // handler, so a provider added at runtime is live within the next
351	      // HTTP request — no kernel restart.
352	      //
353	      // SECURITY POSTURE:
354	      //   - Admin-only: every route calls `auth:require-user` and rejects
355	      //     401 (unauthenticated) / 403 (non-admin).
356	      //   - Input is bounded + enum-validated in the store (Invariant I5).
357	      //   - GET strips `clientSecret` before responding (Invariant I9 —
358	      //     plaintext secrets never leak through hook returns OR the
359	      //     wire). The store's `list()` returns secrets for the rebuild
360	      //     path; the route is responsible for the wire-side strip.
361	      //   - Error messages NEVER echo `clientSecret`. The validators in
362	      //     providers-store.ts deliberately omit value echoes.
363	      await registerAdminRoutes({
364	        bus,
365	        initCtx,
366	        store,
367	        unregisterRoutes,
368	      });
369	    },
370	
371	    async shutdown() {
372	      while (unregisterRoutes.length > 0) {
373	        const fn = unregisterRoutes.pop();
374	        try {
375	          fn?.();
376	        } catch {
377	          // best-effort
378	        }
379	      }
380	      busRef?.unsubscribe('auth:providers-changed', PROVIDERS_CHANGED_KEY);
381	      busRef?.unsubscribe('bootstrap:reset-cleanup', RESET_CLEANUP_KEY);
382	      busRef = undefined;
383	      handle = undefined;
384	      db = undefined;
385	    },
386	  };
387	}
388	
389	// ---------------------------------------------------------------------------
390	// Helpers — kept inline for now; Task 1.5 may extract a `store.ts` if they
391	// grow. The kysely-direct calls are short enough that a separate module
392	// adds more boilerplate than it removes.
393	// ---------------------------------------------------------------------------
394	
395	async function loadProviders(
396	  db: Kysely<AuthBetterDatabase>,
397	  bus: HookBus,
398	  ctx: AgentContext,
399	): Promise<ProviderRow[]> {
400	  const rows = await db
401	    .selectFrom('auth_providers')
402	    .where('enabled', '=', true)
403	    .selectAll()
404	    .execute();
405	
406	  // Short-circuit: no rows → no envelope-decrypt calls. This is the seam
407	  // that lets the bootstrap-user contract test boot @ax/auth-better
408	  // without @ax/credentials registered. Once Task 1.5's CRUD inserts a
409	  // real row, hosts MUST load @ax/credentials too — that's tracked in
410	  // the half-wired-window note.
411	  if (rows.length === 0) return [];
412	
413	  const out: ProviderRow[] = [];
414	  for (const r of rows) {
415	    const { plaintext } = await bus.call<
416	      { ciphertext: Uint8Array },
417	      { plaintext: string }
418	    >('credentials:envelope-decrypt', ctx, { ciphertext: r.client_secret_encrypted });
419	    if (r.kind === 'google' || r.kind === 'github' || r.kind === 'oidc') {
420	      // Build the row carefully: `discoveryUrl` is optional in the
421	      // ProviderRow type (exactOptionalPropertyTypes is ON), so emit
422	      // the field only when DB has a value. Conditional spread keeps
423	      // the shape clean.
424	      out.push({
425	        kind: r.kind,
426	        clientId: r.client_id,
427	        clientSecret: plaintext,
428	        ...(r.discovery_url !== null ? { discoveryUrl: r.discovery_url } : {}),
429	      });
430	    }
431	    // Unknown kinds are dropped — defensive against a forward-compat row
432	    // older binaries can't speak. Logging is deferred to Task 1.5 (the
433	    // CRUD layer is the right place to surface unknown kinds).
434	  }
435	  return out;
436	}
437	
438	async function requireUser(
439	  db: Kysely<AuthBetterDatabase>,
440	  sessionCookieName: string,
441	  req: HttpRequestLike,
442	): Promise<{ user: User }> {
443	  const sessionId = req.signedCookie(sessionCookieName);
444	  if (sessionId === null) {
445	    throw new PluginError({
446	      code: 'unauthenticated',
447	      plugin: PLUGIN_NAME,
448	      hookName: 'auth:require-user',
449	      message: 'no session cookie',
450	    });
451	  }
452	  const row = await db
453	    .selectFrom('auth_better_v1_sessions')
454	    .innerJoin(
455	      'auth_better_v1_users',
456	      'auth_better_v1_users.id',
457	      'auth_better_v1_sessions.user_id',
458	    )
459	    .where('auth_better_v1_sessions.token', '=', sessionId)
460	    .where('auth_better_v1_sessions.expires_at', '>', new Date())
461	    .select([
462	      'auth_better_v1_users.id',
463	      'auth_better_v1_users.email',
464	      'auth_better_v1_users.name',
465	      'auth_better_v1_users.role',
466	    ])
467	    .executeTakeFirst();
468	  if (row === undefined) {
469	    throw new PluginError({
470	      code: 'unauthenticated',
471	      plugin: PLUGIN_NAME,
472	      hookName: 'auth:require-user',
473	      message: 'session unknown or expired',
474	    });
475	  }
476	  return { user: rowToUser(row) };
477	}
478	
479	async function getUserById(
480	  db: Kysely<AuthBetterDatabase>,
481	  userId: string,
482	): Promise<User | null> {
483	  if (typeof userId !== 'string' || userId.length === 0) {
484	    throw new PluginError({
485	      code: 'invalid-payload',
486	      plugin: PLUGIN_NAME,
487	      hookName: 'auth:get-user',
488	      message: 'userId must be a non-empty string',
489	    });
490	  }
491	  const row = await db
492	    .selectFrom('auth_better_v1_users')
493	    .where('id', '=', userId)
494	    .select(['id', 'email', 'name', 'role'])
495	    .executeTakeFirst();
496	  return row === undefined ? null : rowToUser(row);
497	}
498	
499	async function createBootstrapUser(
500	  db: Kysely<AuthBetterDatabase>,
501	  sessionLifetimeSeconds: number,
502	  input: CreateBootstrapUserInput,
503	): Promise<CreateBootstrapUserOutput> {
504	  // Validate untrusted input (I5). The bootstrap caller is the
505	  // unauthenticated onboarding UI — every field arrives from the wire.
506	  if (typeof input.displayName !== 'string') {
507	    throw new PluginError({
508	      code: 'invalid-payload',
509	      plugin: PLUGIN_NAME,
510	      hookName: 'auth:create-bootstrap-user',
511	      message: 'displayName must be a string',
512	    });
513	  }
514	  if (input.displayName.length > MAX_DISPLAY_NAME_LEN) {
515	    throw new PluginError({
516	      code: 'invalid-payload',
517	      plugin: PLUGIN_NAME,
518	      hookName: 'auth:create-bootstrap-user',
519	      message: `displayName exceeds ${MAX_DISPLAY_NAME_LEN} characters`,
520	    });
521	  }
522	  if (input.email !== undefined) {
523	    if (typeof input.email !== 'string' || input.email.length === 0) {
524	      throw new PluginError({
525	        code: 'invalid-payload',
526	        plugin: PLUGIN_NAME,
527	        hookName: 'auth:create-bootstrap-user',
528	        message: 'email must be a non-empty string when provided',
529	      });
530	    }
531	    if (input.email.length > MAX_EMAIL_LEN) {
532	      throw new PluginError({
533	        code: 'invalid-payload',
534	        plugin: PLUGIN_NAME,
535	        hookName: 'auth:create-bootstrap-user',
536	        message: `email exceeds ${MAX_EMAIL_LEN} characters`,
537	      });
538	    }
539	    if (!EMAIL_RE.test(input.email)) {
540	      throw new PluginError({
541	        code: 'invalid-payload',
542	        plugin: PLUGIN_NAME,
543	        hookName: 'auth:create-bootstrap-user',
544	        message: 'email must look like an email address',
545	      });
546	    }
547	  }
548	
549	  // I6: bootstrap is one-shot. Refuse if any admin already exists.
550	  // (Task 2.2 hardens this further — a follow-up bootstrap-completed
551	  // marker lands then. For 1.4 the admin-row check is the gate.)
552	  const existing = await db
553	    .selectFrom('auth_better_v1_users')
554	    .where('role', '=', 'admin')
555	    .select('id')
556	    .executeTakeFirst();
557	  if (existing !== undefined) {
558	    throw new PluginError({
559	      code: 'admin-already-exists',
560	      plugin: PLUGIN_NAME,
561	      hookName: 'auth:create-bootstrap-user',
562	      message: 'admin already exists; bootstrap refused',
563	    });
564	  }
565	
566	  const id = `usr_${randomBytes(16).toString('hex')}`;
567	  const email =
568	    input.email !== undefined && input.email.length > 0
569	      ? input.email
570	      : `bootstrap+${id}@local.invalid`;
571	  const displayName = input.displayName.length > 0 ? input.displayName : null;
572	  const now = new Date();
573	
574	  // Mint a 32-byte token; store it as the session row. The token IS the
575	  // session cookie value — Task 2 (onboarding flow) hands the bootstrap
576	  // CLI the token and exchanges it for a Set-Cookie immediately.
577	  const oneTimeToken = randomBytes(32).toString('base64url');
578	  const sessionId = `sess_${randomBytes(16).toString('hex')}`;
579	  const expiresAt = new Date(Date.now() + sessionLifetimeSeconds * 1000);
580	
581	  // Wrap both inserts in a transaction so a session-insert failure
582	  // (constraint violation, transient pg error, etc.) rolls back the
583	  // user insert too. Without this, an orphaned admin row would block
584	  // every subsequent bootstrap call with `admin-already-exists` —
585	  // recovery would require a DB reset. With the transaction, a failed
586	  // bootstrap leaves the table in its pre-call state and the operator
587	  // can simply retry.
588	  return await db.transaction().execute(async (trx) => {
589	    await trx
590	      .insertInto('auth_better_v1_users')
591	      .values({
592	        id,
593	        email,
594	        email_verified: false,
595	        name: displayName,
596	        image: null,
597	        role: 'admin',
598	        created_at: now,
599	        updated_at: now,
600	      })
601	      .execute();
602	
603	    await trx
604	      .insertInto('auth_better_v1_sessions')
605	      .values({
606	        id: sessionId,
607	        user_id: id,
608	        token: oneTimeToken,
609	        expires_at: expiresAt,
610	        ip_address: null,
611	        user_agent: null,
612	        created_at: now,
613	        updated_at: now,
614	      })
615	      .execute();
616	
617	    const userRow = { id, email, name: displayName, role: 'admin' as const };
618	    return { user: rowToUser(userRow), oneTimeToken };
619	  });
620	}
621	
622	function rowToUser(row: {
623	  id: string;
624	  email: string;
625	  name: string | null;
626	  role: 'admin' | 'user';
627	}): User {
628	  return {
629	    id: row.id,
630	    // Table column is NOT NULL; User type is `string | null`. Pass the
631	    // string through — the User boundary type is the contract, not the
632	    // table shape.
633	    email: row.email,
634	    displayName: row.name,
635	    isAdmin: row.role === 'admin',
636	  };
637	}
638	
639	// ---------------------------------------------------------------------------
640	// HTTP adapter — bridges @ax/http-server's HttpRequest/HttpResponse to
641	// the WebStandards Request/Response that better-auth's handler expects.
642	//
643	// The /auth/* splat is registered for every method we expect better-auth
644	// to route. The adapter:
645	//   1. Builds a fetch.Request from HttpRequest (URL = path + query, body
646	//      = req.body when present, headers as-is).
647	//   2. Invokes handle.current()(webRequest) → fetch.Response.
648	//   3. Translates the Response back: status, every header (including
649	//      multi-value Set-Cookie), and the raw body bytes.
650	//
651	// Cookies: better-auth's session cookies ride on the standard Set-Cookie
652	// header. http-server's response writer stores headers in a Map, so we
653	// can only set one Set-Cookie value at a time — we collect every
654	// Set-Cookie better-auth emits and join them with ', ' before calling
655	// res.header('set-cookie', …) ONCE. See the dedicated comment near the
656	// join below for the RFC/UA-compatibility rationale.
657	// ---------------------------------------------------------------------------
658	
659	async function forwardToBetterAuth(
660	  handle: HandlerHandle,
661	  req: HttpRequest,
662	  res: HttpResponse,
663	): Promise<void> {
664	  // Synthesize an absolute URL — better-auth's internal router parses
665	  // it via WHATWG URL. Hostname doesn't matter; better-auth keys off
666	  // the pathname + search.
667	  const host = req.headers['host'] ?? 'localhost';
668	  const proto = req.headers['x-forwarded-proto'] ?? 'http';
669	  const queryString = serializeQuery(req.query);
670	  const url = `${proto}://${host}${req.path}${queryString.length > 0 ? `?${queryString}` : ''}`;
671	
672	  // Fetch.Request rejects bodies on GET (and HEAD, which @ax/http-server
673	  // doesn't expose anyway). Pass body only when there's something to send.
674	  const init: RequestInit = {
675	    method: req.method,
676	    headers: webHeadersFrom(req.headers),
677	  };
678	  if (req.method !== 'GET' && req.body.length > 0) {
679	    // Node's undici fetch accepts a Buffer/Uint8Array as body even
680	    // though the lib.dom typing of `BodyInit` doesn't include Buffer
681	    // specifically. Cast through unknown to satisfy the structural
682	    // check without dragging the dom type in.
683	    init.body = req.body as unknown as ArrayBuffer;
684	  }
685	
686	  let webResponse: Response;
687	  try {
688	    webResponse = await handle.current()(new Request(url, init));
689	  } catch (err) {
690	    // If better-auth's adapter init failed (handler.ts catches the
691	    // construction-side rejection but request-time rejections still
692	    // propagate), surface a 500 without leaking the inner message —
693	    // better-auth's errors can echo request-derived fields (state,
694	    // email, callback URL params), so we omit `err.message` from the
695	    // log line entirely. Method + path is enough to correlate with
696	    // upstream http-server access logs.
697	    void err;
698	    process.stderr.write(
699	      `[ax/auth-better] handler error on ${req.method} ${req.path}\n`,
700	    );
701	    res.status(500).json({ error: 'auth-handler-failed' });
702	    return;
703	  }
704	
705	  res.status(webResponse.status);
706	
707	  // Copy all headers. fetch.Headers normalizes names to lowercase;
708	  // multi-value headers (Set-Cookie) come through `getSetCookie()` on
709	  // node's undici fetch.
710	  const setCookies = readSetCookies(webResponse.headers);
711	  for (const [name, value] of webResponse.headers.entries()) {
712	    if (name.toLowerCase() === 'set-cookie') continue;
713	    // content-type is set on the response writer below via body() — but
714	    // better-auth doesn't always set one; we forward whatever it gave us.
715	    res.header(name, value);
716	  }
717	  if (setCookies.length > 0) {
718	    // http-server's response writer stores headers in a Map
719	    // (last-write-wins), so calling res.header('set-cookie', …) once
720	    // per cookie would silently drop all but the last value. Until
721	    // http-server gains a multi-value header API, we collapse every
722	    // Set-Cookie into a single comma-joined header. Per RFC 6265 §3
723	    // and the de-facto behavior of all major user agents, comma-joined
724	    // Set-Cookie values are parsed correctly when the individual
725	    // cookie attributes don't contain unquoted commas — which
726	    // better-auth's emitted cookies do not. A future http-server
727	    // change to support multi-value headers would let us emit one
728	    // Set-Cookie per cookie; until then, this preserves all cookies
729	    // in one header line so session + CSRF (and clear-old + set-new
730	    // on rotation) both reach the browser.
731	    res.header('set-cookie', setCookies.join(', '));
732	  }
733	
734	  const buf = Buffer.from(await webResponse.arrayBuffer());
735	  if (buf.length === 0) {
736	    res.end();
737	  } else {
738	    // res.body() preserves any prior content-type from the loop above.
739	    res.body(buf);
740	  }
741	}
742	
743	function webHeadersFrom(in_: Record<string, string>): Headers {
744	  const h = new Headers();
745	  for (const [k, v] of Object.entries(in_)) {
746	    if (typeof v !== 'string') continue;
747	    try {
748	      h.set(k, v);
749	    } catch {
750	      // Skip headers Headers refuses (forbidden names, invalid bytes).
751	      // Forwarding `host` etc. into an outbound Request is fine; node's
752	      // fetch only rejects on truly invalid characters.
753	    }
754	  }
755	  return h;
756	}
757	
758	function readSetCookies(h: Headers): string[] {
759	  // Node 20.4+ supports getSetCookie(); fall back to a single header
760	  // value if the runtime is older.
761	  const dyn = h as unknown as { getSetCookie?: () => string[] };
762	  if (typeof dyn.getSetCookie === 'function') {
763	    return dyn.getSetCookie();
764	  }
765	  const single = h.get('set-cookie');
766	  return single === null ? [] : [single];
767	}
768	
769	function serializeQuery(query: Record<string, string>): string {
770	  const pairs: string[] = [];
771	  for (const [k, v] of Object.entries(query)) {
772	    pairs.push(`${encodeURIComponent(k)}=${encodeURIComponent(v)}`);
773	  }
774	  return pairs.join('&');
775	}
776	
777	// ---------------------------------------------------------------------------
778	// /admin/auth/providers/* — admin-only runtime CRUD.
779	//
780	// Routes:
781	//   GET    /admin/auth/providers      → list (secrets STRIPPED)
782	//   POST   /admin/auth/providers      → upsert
783	//   PATCH  /admin/auth/providers/:kind → setEnabled
784	//   DELETE /admin/auth/providers/:kind → delete
785	//
786	// Each mutation fires `auth:providers-changed` on success; the subscriber
787	// registered in init() rebuilds the handler in place — closing I10.
788	// ---------------------------------------------------------------------------
789	
790	interface RegisterAdminRoutesDeps {
791	  bus: HookBus;
792	  initCtx: AgentContext;
793	  store: ProvidersStore;
794	  unregisterRoutes: Array<() => void>;
795	}
796	
797	async function registerAdminRoutes(deps: RegisterAdminRoutesDeps): Promise<void> {
798	  const { bus, initCtx, store, unregisterRoutes } = deps;
799	
800	  const register = async (method: HttpMethod, path: string, handler: (req: HttpRequest, res: HttpResponse) => Promise<void>): Promise<void> => {
801	    const { unregister } = await bus.call<HttpRegisterRouteInput, HttpRegisterRouteOutput>(
802	      'http:register-route',
803	      initCtx,
804	      { method, path, handler },
805	    );
806	    unregisterRoutes.push(unregister);
807	  };
808	
809	  await register('GET', '/admin/auth/providers', async (req, res) => {
810	    if (!(await requireAdmin(bus, initCtx, req, res))) return;
811	    const rows = await store.list();
812	    // Strip clientSecret before going on the wire (Invariant I9). The
813	    // route is the LAST line of defense — the store deliberately returns
814	    // plaintext for the rebuild path, so we strip explicitly here rather
815	    // than overload the store with two read modes.
816	    const sanitized = rows.map((r) => ({
817	      kind: r.kind,
818	      clientId: r.clientId,
819	      discoveryUrl: r.discoveryUrl,
820	      allowedDomains: r.allowedDomains,
821	      enabled: r.enabled,
822	      createdAt: r.createdAt.toISOString(),
823	      updatedAt: r.updatedAt.toISOString(),
824	    }));
825	    res.status(200).json({ providers: sanitized });
826	  });
827	
828	  await register('POST', '/admin/auth/providers', async (req, res) => {
829	    if (!(await requireAdmin(bus, initCtx, req, res))) return;
830	    const body = parseJsonBody(req.body);
831	    if (body === null) {
832	      res.status(400).json({ error: 'invalid-json' });
833	      return;
834	    }
835	    try {
836	      await store.upsert({
837	        kind: asString(body.kind),
838	        clientId: asString(body.clientId),
839	        clientSecret: asString(body.clientSecret),
840	        ...(body.discoveryUrl !== undefined
841	          ? { discoveryUrl: asString(body.discoveryUrl) }
842	          : {}),
843	        ...(body.allowedDomains !== undefined
844	          ? { allowedDomains: asString(body.allowedDomains) }
845	          : {}),
846	      });
847	    } catch (err) {
848	      sendValidationError(res, err);
849	      return;
850	    }
851	    await bus.fire('auth:providers-changed', initCtx, {});
852	    res.status(201).json({ ok: true });
853	  });
854	
855	  await register('PATCH', '/admin/auth/providers/:kind', async (req, res) => {
856	    if (!(await requireAdmin(bus, initCtx, req, res))) return;
857	    const kind = req.params['kind'] ?? '';
858	    const body = parseJsonBody(req.body);
859	    if (body === null) {
860	      res.status(400).json({ error: 'invalid-json' });
861	      return;
862	    }
863	    if (typeof body.enabled !== 'boolean') {
864	      res.status(400).json({ error: 'invalid-payload', message: 'enabled must be a boolean' });
865	      return;
866	    }
867	    try {
868	      await store.setEnabled(kind, body.enabled);
869	    } catch (err) {
870	      sendValidationError(res, err);
871	      return;
872	    }
873	    await bus.fire('auth:providers-changed', initCtx, {});
874	    res.status(200).json({ ok: true });
875	  });
876	
877	  await register('DELETE', '/admin/auth/providers/:kind', async (req, res) => {
878	    if (!(await requireAdmin(bus, initCtx, req, res))) return;
879	    const kind = req.params['kind'] ?? '';
880	    try {
881	      await store.delete(kind);
882	    } catch (err) {
883	      sendValidationError(res, err);
884	      return;
885	    }
886	    await bus.fire('auth:providers-changed', initCtx, {});
887	    res.status(204).end();
888	  });
889	}
890	
891	/**
892	 * Calls `auth:require-user` against the bus and emits 401/403 directly on
893	 * the response. Returns `true` if the caller is an admin (route handler
894	 * should continue) or `false` if a response was already sent (handler
895	 * should return immediately).
896	 *
897	 * The hook is OUR own service — calling it via the bus rather than reaching
898	 * into the impl directly keeps the helper interchangeable with a future
899	 * alternate auth impl that registers the same surface.
900	 */
901	async function requireAdmin(
902	  bus: HookBus,
903	  ctx: AgentContext,
904	  req: HttpRequest,
905	  res: HttpResponse,
906	): Promise<boolean> {
907	  let user: User;
908	  try {
909	    const out = await bus.call<{ req: HttpRequestLike }, { user: User }>(
910	      'auth:require-user',
911	      ctx,
912	      { req },
913	    );
914	    user = out.user;
915	  } catch (err) {
916	    if (err instanceof PluginError && err.code === 'unauthenticated') {
917	      res.status(401).json({ error: 'unauthenticated' });
918	      return false;
919	    }
920	    // Unknown failure — surface a 500 without leaking the cause.
921	    res.status(500).json({ error: 'auth-check-failed' });
922	    return false;
923	  }
924	  if (!user.isAdmin) {
925	    res.status(403).json({ error: 'forbidden' });
926	    return false;
927	  }
928	  return true;
929	}
930	
931	function parseJsonBody(body: Buffer): Record<string, unknown> | null {
932	  if (body.length === 0) return {};
933	  try {
934	    const parsed = JSON.parse(body.toString('utf8')) as unknown;
935	    if (parsed === null || typeof parsed !== 'object' || Array.isArray(parsed)) {
936	      return null;
937	    }
938	    return parsed as Record<string, unknown>;
939	  } catch {
940	    return null;
941	  }
942	}
943	
944	function asString(v: unknown): string {
945	  // Cheap normalization for the validators downstream — they re-check
946	  // type/length. We only convert here so a missing field surfaces as
947	  // empty-string and validation rejects it cleanly.
948	  return typeof v === 'string' ? v : '';
949	}
950	
951	function sendValidationError(res: HttpResponse, err: unknown): void {
952	  if (err instanceof PluginError && err.code === 'invalid-payload') {
953	    // Safe: PluginError messages from providers-store.ts are static,
954	    // never include the raw secret value.
955	    res.status(400).json({ error: 'invalid-payload', message: err.message });
956	    return;
957	  }
958	  // Anything else — log NOTHING about the body and return a generic 500.
959	  // Even an unexpected DB error mustn't echo a payload field.
960	  res.status(500).json({ error: 'internal' });
961	}
